24	/// Directory where the detached finalize child writes failure markers.
25	/// A subsequent `vc-x1` invocation scans this directory and surfaces
26	/// any failures to the user, closing the gap that the detached child's
27	/// non-zero exit isn't observable by the caller.
28	fn status_dir() -> Option<PathBuf> {
29	    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
30	}
31	
32	/// Drop a failure marker for the detached child whose non-zero exit
33	/// the caller can't observe.
34	///
35	/// - The error is flattened to one line so the marker keeps its
36	///   one-`key=value`-per-line shape (errors may wrap for terminal
37	///   readability).
38	fn write_failure_marker(params: &FinalizeParams, err: &str) {
39	    let Some(dir) = status_dir() else {
40	        return;
41	    };
42	    if std::fs::create_dir_all(&dir).is_err() {
43	        return;
44	    }
45	    let ns = SystemTime::now()
46	        .duration_since(UNIX_EPOCH)
47	        .map(|d| d.as_nanos())
48	        .unwrap_or(0); // OK: filesystem-sortable timestamp; 0 on the impossible pre-epoch path
49	    let pid = std::process::id();
50	    let path = dir.join(format!("{ns}-{pid}.status"));
51	    let err_flat = err.split_whitespace().collect::<Vec<_>>().join(" ");
52	    let content = format!(
53	        "timestamp_ns={ns}\npid={pid}\nrepo={}\nbookmark={}\nerror={err_flat}\n",
54	        params.repo.display(),
55	        params.bookmark.as_deref().unwrap_or(""),
56	    );
57	    let _ = std::fs::write(&path, content);
58	}
