60	/// Read, print, and delete any failure markers left by previous detached
61	/// finalize children. Cheap no-op when the directory doesn't exist.
62	///
63	/// - Called after the current command's output (see `main`), so the
64	///   block opens with a loud banner marking everything below it as
65	///   historical — failures from earlier detached runs, not this one.
66	pub fn surface_previous_failures() {
67	    let Some(dir) = status_dir() else {
68	        return;
69	    };
70	    let Ok(entries) = std::fs::read_dir(&dir) else {
71	        return;
72	    };
73	    let mut paths: Vec<PathBuf> = entries
74	        .flatten()
75	        .map(|e| e.path())
76	        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
77	        .collect();
78	    paths.sort();
79	    if paths.is_empty() {
80	        return;
81	    }
82	    eprintln!("warn: ==== failure(s) from previous detached finalize run(s) ====");
83	    for path in paths {
84	        if let Ok(content) = std::fs::read_to_string(&path) {
85	            eprintln!(
86	                "warn: previous detached finalize failed ({}):",
87	                path.file_stem()
88	                    .map(|s| s.to_string_lossy())
89	                    .unwrap_or_default() // OK: filename without extension; empty on unexpected absence
90	            );
91	            for line in content.lines() {
92	                eprintln!("  {line}");
93	            }
94	            let _ = std::fs::remove_file(&path);
95	        }
96	    }
97	}
