99	/// Squash, set bookmark, and/or push a jj repo.
100	///
101	/// Designed for the bot to atomically finalize its session repo:
102	/// --detach exits immediately, --delay waits for trailing writes,
103	/// --squash folds them in, --bookmark + --push sends it upstream.
104	/// Every flag is opt-in. See README.md for details.
105	#[derive(Args, Debug)]
106	pub struct FinalizeArgs {
107	    /// Path to jj repo
108	    #[arg(long, default_value = ".")]
109	    pub repo: PathBuf,
110	
111	    #[command(flatten)]
112	    pub squash: SquashOption,
113	
114	    /// Seconds to wait before squashing
115	    #[arg(long, default_value_t = 10.0)]
116	    pub delay: f64,
117	
118	    /// Existing bookmark to push to remote
119	    #[arg(long, value_name = "BOOKMARK")]
120	    pub push: Option<String>,
121	
122	    /// Detach and run in the background
123	    #[arg(long)]
124	    pub detach: bool,
125	
126	    /// The above `pub detach` is true when `--detach` is passed
127	    /// to the `finalize` subcommand. The app then `fork`s and
128	    /// spawns `vc-x1 finalize --exec …`, replacing `--detach`
129	    /// with `--exec`. The child sees `exec: true` and is routed
130	    /// through `finalize_exec()` to do the squash/push work in
131	    /// the background.
132	    ///
133	    /// Marked `hide = true` because it's an internal argument and
134	    /// should not appear in `-h` / `--help` output.
135	    #[arg(long, hide = true)]
136	    pub exec: bool,
137	}
