296	/// Extract the values of column-0 `ochid:` trailer lines from a
297	/// commit description, in order of appearance.
298	fn extract_ochids(desc: &str) -> Vec<String> {
299	    desc.lines()
300	        .filter_map(|line| line.strip_prefix("ochid:"))
301	        .map(|value| value.trim().to_string())
302	        .filter(|value| !value.is_empty())
303	        .collect()
304	}
305	
306	/// Return the `ochid:` trailer values present in `source_desc` but
307	/// absent from `target_desc` — the trailers a squash with
308	/// `--use-destination-message` would silently drop (Bugs #1).
309	fn ochids_at_risk(source_desc: &str, target_desc: &str) -> Vec<String> {
310	    let kept = extract_ochids(target_desc);
311	    extract_ochids(source_desc)
312	        .into_iter()
313	        .filter(|ochid| !kept.contains(ochid))
314	        .collect()
315	}
316	
317	/// Refuse a squash that would drop the source message's `ochid:`
318	/// trailers.
319	///
320	/// - Compares the two messages' `ochid:` trailers; errors when the
321	///   source carries any the destination's message lacks —
322	///   `--use-destination-message` would discard them, leaving the
323	///   counterpart repo's cross-links dangling (Bugs #1).
324	/// - Called from `preflight` (visible early failure) and again in
325	///   `finalize_exec` right before the squash (authoritative — a
326	///   `jj describe` can land between preflight and the delayed
327	///   squash).
328	fn check_squash_keeps_ochids(
329	    repo: &str,
330	    cwd: &std::path::Path,
331	    sq: &SquashSpec,
332	) -> Result<(), Box<dyn std::error::Error>> {
333	    let desc_of = |rev: &str| {
334	        run(
335	            "jj",
336	            &[
337	                "log",
338	                "-r",
339	                rev,
340	                "--no-graph",
341	                "-T",
342	                "description",
343	                "-R",
344	                repo,
345	            ],
346	            cwd,
347	        )
348	    };
349	    let at_risk = ochids_at_risk(&desc_of(&sq.source)?, &desc_of(&sq.target)?);
350	    if at_risk.is_empty() {
351	        return Ok(());
352	    }
353	    let listed = at_risk
354	        .iter()
355	        .map(|ochid| format!("  {ochid}"))
356	        .collect::<Vec<_>>()
357	        .join("\n");
358	    Err(format!(
359	        "refusing squash {} → {}: the squash would drop ochid: trailers\n\
360	         the destination's message lacks:\n\
361	         {listed}\n\
362	         merge the messages by hand (`jj describe {} -R {}`) or clear\n\
363	         the source's description, then retry",
364	        sq.source, sq.target, sq.target, repo,
365	    )
366	    .into())
367	}
