369	/// Return Ok(()) if the revset resolves to one or more commits in `repo`.
370	fn jj_rev_exists(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<(), String> {
371	    run(
372	        "jj",
373	        &["log", "-r", rev, "--no-graph", "-T", "\"x\"", "-R", repo],
374	        cwd,
375	    )
376	    .map_err(|e| e.to_string())?;
377	    Ok(())
378	}
