380	/// Log what finalize is about to do so the user sees the plan before detach.
381	fn log_plan(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
382	    let repo_str = params.repo.to_string_lossy();
383	    let cwd = std::path::Path::new(".");
384	
385	    if let Some(ref sq) = params.squash {
386	        info!(
387	            "finalize: squash {} → {} in {}",
388	            sq.source, sq.target, repo_str
389	        );
390	    }
391	    if let Some(ref bookmark) = params.bookmark {
392	        let target_rev = params
393	            .squash
394	            .as_ref()
395	            .map(|sq| sq.target.as_str())
396	            .unwrap_or("@"); // OK: same as above
397	        let current = jj_rev_short(&repo_str, cwd, bookmark).unwrap_or_else(|_| "?".into()); // OK: logging only — fall back to "?" if revset fails
398	        let target = jj_rev_short(&repo_str, cwd, target_rev).unwrap_or_else(|_| "?".into()); // OK: same
399	        info!("finalize: set bookmark '{bookmark}' {current} → {target} ({target_rev})");
400	        if params.push {
401	            info!("finalize: push '{bookmark}' to remote");
402	        }
403	    }
404	
405	    Ok(())
406	}
