427	/// Do the squash / set-bookmark / push work — runs in the detached
428	/// child when `--detach`, inline otherwise.
429	fn finalize_exec(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
430	    debug!("finalize_exec: starting params={params:?}");
431	    let repo_str = params.repo.to_string_lossy();
432	    let cwd = std::path::Path::new(".");
433	
434	    // Squash if requested
435	    if let Some(ref sq) = params.squash {
436	        let delay = std::time::Duration::from_secs_f64(params.delay_secs);
437	        debug!("finalize_exec: sleeping {delay:?}");
438	        std::thread::sleep(delay);
439	
440	        // Re-check after the delay: a `jj describe` can land between
441	        // the parent's preflight and this point, so the pre-squash
442	        // state is the one that matters.
443	        check_squash_keeps_ochids(&repo_str, cwd, sq)?;
444	
445	        info!("finalize: squashing {} → {}...", sq.source, sq.target);
446	        run(
447	            "jj",
448	            &[
449	                "squash",
450	                "--ignore-immutable",
451	                "--use-destination-message",
452	                "--from",
453	                &sq.source,
454	                "--into",
455	                &sq.target,
456	                "-R",
457	                &repo_str,
458	            ],
459	            cwd,
460	        )?;
461	    }
462	
463	    // Set bookmark and push if requested
464	    if let Some(ref bookmark) = params.bookmark {
465	        // Verify bookmark exists — don't silently create new ones
466	        let result = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
467	        if result.is_empty() {
468	            return Err(format!("bookmark '{bookmark}' does not exist").into());
469	        }
470	
471	        let rev = params
472	            .squash
473	            .as_ref()
474	            .map(|sq| sq.target.as_str())
475	            .unwrap_or("@"); // OK: no squash spec → bookmark points at current @
476	        info!("finalize: setting bookmark '{bookmark}' to {rev}...");
477	        run(
478	            "jj",
479	            &["bookmark", "set", bookmark, "-r", rev, "-R", &repo_str],
480	            cwd,
481	        )?;
482	
483	        if params.push {
484	            info!("finalize: pushing '{bookmark}' to origin...");
485	            run(
486	                "jj",
487	                &["git", "push", "--bookmark", bookmark, "-R", &repo_str],
488	                &params.repo,
489	            )?;
490	        }
491	    }
492	
493	    info!("finalize: done");
494	    debug!("finalize_exec: done");
495	    Ok(())
496	}
