498	/// Build the argv for the detached re-exec: `finalize --exec …`,
499	/// mirroring `params` plus the `--log` path so the child logs to
500	/// the same file.
501	pub fn build_exec_args(params: &FinalizeParams, log: Option<&Path>) -> Vec<String> {
502	    let mut args = vec![
503	        "finalize".to_string(),
504	        "--exec".to_string(),
505	        "--repo".to_string(),
506	        params.repo.to_string_lossy().to_string(),
507	    ];
508	    if let Some(ref sq) = params.squash {
509	        args.push("--squash".to_string());
510	        args.push(format!("{},{}", sq.source, sq.target));
511	        args.push("--delay".to_string());
512	        args.push(params.delay_secs.to_string());
513	    }
514	    if let Some(ref bookmark) = params.bookmark {
515	        args.push("--push".to_string());
516	        args.push(bookmark.clone());
517	    }
518	    if let Some(log) = log {
519	        args.push("--log".to_string());
520	        args.push(log.to_string_lossy().to_string());
521	    }
522	    args
523	}
