525	/// Spawn a detached child process with `--exec` and return immediately.
526	/// The child re-enters `main()`, parses `--exec`, and `finalize()` routes
527	/// it to `finalize_exec()` where the actual work happens.
528	fn detach(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
529	    debug!("detach: parent starting params={params:?}");
530	
531	    let exe = std::env::current_exe()?;
532	    let args = build_exec_args(params, ctx.log.as_deref());
533	    debug!("detach: exe={exe:?} args={args:?}");
534	
535	    let mut cmd = std::process::Command::new(exe);
536	    cmd.args(&args).stdin(Stdio::null());
537	
538	    // Hand the child the user's controlling terminal when one exists so
539	    // its output stays visible after the parent exits. Inherited pipes
540	    // are unreliable here — the bash-tool / cron caller typically closes
541	    // its read end on parent exit, silently dropping child writes. Fall
542	    // back to null when there is no tty (pipe-invoked / CI / Windows);
543	    // the log file is authoritative in that case.
544	    match std::fs::OpenOptions::new()
545	        .read(true)
546	        .write(true)
547	        .open("/dev/tty")
548	    {
549	        Ok(tty) => {
550	            debug!("detach: /dev/tty opened, child output → terminal");
551	            let out = tty.try_clone()?;
552	            cmd.stdout(Stdio::from(out));
553	            cmd.stderr(Stdio::from(tty));
554	        }
555	        Err(e) => {
556	            debug!("detach: /dev/tty unavailable ({e}), child output → null");
557	            cmd.stdout(Stdio::null());
558	            cmd.stderr(Stdio::null());
559	        }
560	    }
561	
562	    #[cfg(unix)]
563	    {
564	        use std::os::unix::process::CommandExt;
565	        unsafe {
566	            cmd.pre_exec(|| {
567	                libc::setsid();
568	                Ok(())
569	            });
570	        }
571	    }
572	
573	    let child = cmd.spawn()?;
574	    debug!("detach: spawned child pid={}", child.id());
575	    match &ctx.log {
576	        Some(log) => info!(
577	            "finalize: detached (pid {}), log: {}",
578	            child.id(),
579	            log.display()
580	        ),
581	        None => info!("finalize: detached (pid {})", child.id()),
582	    }
583	    Ok(())
584	}
