586	/// Run finalize fully in-process: preflight, then the
587	/// squash / set-bookmark / push work — no detach, no re-exec.
588	///
589	/// Entry point for callers that hold no `Context` and must see
590	/// the outcome synchronously — `vc-x1 push`'s `finalize-claude`
591	/// stage uses this so a session-push failure is a visible push
592	/// failure (Bugs #1: the detached child died silently at sandbox
593	/// teardown). Callers pass `detach: false, exec: false` and
594	/// typically `delay_secs: 0.0`.
595	pub fn finalize_inline(params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
596	    debug!("finalize_inline: entry params={params:?}");
597	    preflight(params)?;
598	    finalize_exec(params)
599	}
