601	/// Run the `finalize` subcommand: preflight, then either detach a
602	/// child to do the work or do it inline.
603	pub fn finalize(ctx: &Context, params: &FinalizeParams) -> Result<(), Box<dyn std::error::Error>> {
604	    // Nothing to do — show help hint
605	    if params.squash.is_none() && !params.push {
606	        return Err("nothing to do (see --help for options)".into());
607	    }
608	
609	    debug!("finalize: entry params={params:?}");
610	
611	    // Validate synchronously before detaching so failures exit with a
612	    // visible non-zero status rather than hiding in the detached child's log.
613	    // Skip in --exec (the re-entered child already passed preflight in the parent).
614	    if !params.exec {
615	        preflight(params)?;
616	    }
617	
618	    let result = if params.detach && !params.exec {
619	        detach(ctx, params)
620	    } else {
621	        finalize_exec(params)
622	    };
623	    match &result {
624	        Ok(()) => debug!("finalize: exit ok"),
625	        Err(e) => {
626	            debug!("finalize: exit err={e}");
627	            // In the detached-child path the caller can't observe our
628	            // non-zero exit. Drop a failure marker so a later vc-x1
629	            // invocation can surface the problem.
630	            if params.exec {
631	                write_failure_marker(params, &e.to_string());
632	            }
633	        }
634	    }
635	    result
636	}
