255	/// Permanent sanity check for the `main`-bookmark tracking state
256	/// in both repos of the dual-repo workspace. Emits one line on
257	/// entry and one on exit of every command. If entry and exit
258	/// differ, the executing command is the culprit; if entry differs
259	/// from the previous command's exit, something *between*
260	/// invocations broke it. Originally added in 0.37.2 as a temporary
261	/// diagnostic; promoted to permanent in 0.37.4 after the user
262	/// reported "happens more than once".
263	///
264	/// Emits at `log::debug!` (since 0.52.0-1) — default runs stay
265	/// quiet, and the signal remains available under `-v` when
266	/// investigating. The detached `finalize --exec` child runs at
267	/// default verbosity so it stays silent without needing a special
268	/// gate at the call site.
269	///
270	/// Walks up from cwd to locate the workspace root (the directory
271	/// whose `.vc-config.toml` has `path = "/"`), then probes `<root>`
272	/// and `<root>/.claude`. Same labeling whether the user runs from
273	/// the app root, from `.claude`, or from any subdir.
274	pub fn bm_track(phase: &str, command_name: &str) {
275	    let header = format!("bm-track {phase} vc-x1 {command_name}");
276	    let root = match common::find_workspace_root() {
277	        Some(r) => r,
278	        None => {
279	            log::debug!("{header}: no-workspace");
280	            return;
281	        }
282	    };
283	    let repos: [(std::path::PathBuf, &str); 2] =
284	        [(root.clone(), "app"), (root.join(".claude"), ".claude")];
285	    let mut parts: Vec<String> = Vec::new();
286	    for (repo, label) in repos {
287	        if !repo.join(".jj").exists() {
288	            parts.push(format!("{label}(main)=no-jj"));
289	            continue;
290	        }
291	        match bm_track_one(&repo, "main", "origin") {
292	            Ok(true) => parts.push(format!("{label}(main)=tracked")),
293	            Ok(false) => parts.push(format!("{label}(main)=NOT_TRACKED")),
294	            Err(e) => parts.push(format!(
295	                "{label}(main)=err({})",
296	                e.lines().next().unwrap_or("")
297	            )),
298	        }
299	    }
300	    log::debug!("{header}: {}", parts.join(", "));
301	}
302	
303	/// Query jj for whether `bookmark` in `repo` is tracking `remote`.
304	/// Returns `Ok(true)` if the tracked-list entry for `bookmark` shows
305	/// an `@<remote>` line (in any form — `@origin:` when synced, or
306	/// `@origin (ahead by N commits):` / similar when divergent — both
307	/// still count as tracking). `Ok(false)` when no such line exists
308	/// (bookmark isn't tracking this remote or doesn't exist). `Err` on
309	/// subprocess failure.
310	fn bm_track_one(repo: &Path, bookmark: &str, remote: &str) -> Result<bool, String> {
311	    let repo_str = repo.to_string_lossy();
312	    let output = std::process::Command::new("jj")
