impl Stage {
    /// Return the stage's kebab-case string identifier (matches what
    /// the CLI accepts via `--from <stage>` and what `PushState`
    /// persists to disk).
    pub fn as_str(self) -> &'static str {
        match self {
            Stage::Preflight => "preflight",
            Stage::Review => "review",
            Stage::Message => "message",
            Stage::CommitApp => "commit-app",
            Stage::CommitClaude => "commit-claude",
            Stage::BookmarkSet => "bookmark-set",
            Stage::PushApp => "push-app",
            Stage::FinalizeClaude => "finalize-claude",
        }
    }

    /// Parse a kebab-case stage name back into a `Stage`.
    ///
    /// Unknown names return `None`; callers should surface a helpful
    /// error rather than silently substituting a default.
    pub fn from_str(name: &str) -> Option<Self> {
        match name {
            "preflight" => Some(Stage::Preflight),
            "review" => Some(Stage::Review),
            "message" => Some(Stage::Message),
            "commit-app" => Some(Stage::CommitApp),
            "commit-claude" => Some(Stage::CommitClaude),
            "bookmark-set" => Some(Stage::BookmarkSet),
            "push-app" => Some(Stage::PushApp),
            "finalize-claude" => Some(Stage::FinalizeClaude),
            _ => None,
        }
    }

    /// The stage that follows this one, or `None` when this is the
    /// last stage (`FinalizeClaude`).
    pub fn next(self) -> Option<Self> {
        match self {
            Stage::Preflight => Some(Stage::Review),
            Stage::Review => Some(Stage::Message),
            Stage::Message => Some(Stage::CommitApp),
            Stage::CommitApp => Some(Stage::CommitClaude),
            Stage::CommitClaude => Some(Stage::BookmarkSet),
            Stage::BookmarkSet => Some(Stage::PushApp),
            Stage::PushApp => Some(Stage::FinalizeClaude),
            Stage::FinalizeClaude => None,
        }
    }

    /// The first stage in the flow — used when no saved state exists.
    pub fn first() -> Self {
        Stage::Preflight
    }
}

/// CLI arguments for the `push` subcommand.
///
/// Flag set mirrors the design in `notes/chores/chores-05.md`. Flags are
/// parsed in 0.37.0-0; their real effects land across the remaining
/// 0.37.0-N steps. See the module docstring for which flags activate
/// when.
#[derive(Args, Debug)]
pub struct PushArgs {
    /// Bookmark to advance in the code repo (positional form of
    /// `--bookmark`). The session repo always advances `main`.
    ///
    /// Accepting a positional lets the common case read as `vc-x1 push main`
    /// without the `--bookmark` ceremony; `--bookmark` is kept as an
    /// alias for scripts and for composition with other args. The two
    /// forms conflict if both supplied.
    #[arg(value_name = "BOOKMARK", conflicts_with = "bookmark")]
    pub bookmark_pos: Option<String>,

    /// Bookmark to advance in the code repo (flag form; see positional).
    #[arg(long, conflicts_with = "bookmark_pos")]
    pub bookmark: Option<String>,

    /// Clear any saved state file and start from stage 1.
    #[arg(long)]
    pub restart: bool,

    /// Explicit stage to jump to (advanced / debug use).
    #[arg(long, value_name = "STAGE")]
    pub from: Option<Stage>,

    /// Pause between every stage for an interactive approval gate.
    #[arg(long)]
    pub step: bool,

    /// Print where the saved state thinks we are and exit.
    #[arg(long)]
    pub status: bool,

    /// Re-run `preflight` even on resume (default: skip if last run succeeded).
    #[arg(long)]
    pub recheck: bool,

    /// Stop before `finalize-claude` so it can be run manually.
    #[arg(long)]
    pub no_finalize: bool,

    /// Print the exact commands for every stage without side effects.
    #[arg(long)]
    pub dry_run: bool,

    /// Commit title (skip `$EDITOR` for the message stage).
    #[arg(long, value_name = "STR")]
    pub title: Option<String>,

    /// Commit body (skip `$EDITOR` for the message stage).
    #[arg(long, value_name = "STR")]
    pub body: Option<String>,

    /// Auto-approve interactive prompts (review gate, message-edit
    /// confirmation). Required when `--title` / `--body` aren't both
    /// supplied in non-interactive contexts.
    #[arg(short = 'y', long)]
    pub yes: bool,
}

/// Inputs to the push op, flat, owned, clap-free.
///
/// Mirrors `PushArgs`, with the two clap bookmark spellings
/// (positional `BOOKMARK` and `--bookmark`) collapsed into one
/// `bookmark` field. The rest map straight over: `restart`, `from`
/// (a `Stage`, a domain type — kept), `step`, `status`, `recheck`,
/// `no_finalize`, `dry_run`, `title`, `body`, `yes`.
pub struct PushParams {
    pub bookmark: Option<String>,
    pub restart: bool,
    pub from: Option<Stage>,
    pub step: bool,
    pub status: bool,
    /// `--recheck` is parsed by `PushArgs` but not yet wired into the
    /// stage machine; carried here so the conversion stays total and
    /// the field is in place when the behavior lands.
    #[allow(dead_code)]
    pub recheck: bool,
    pub no_finalize: bool,
    pub dry_run: bool,
    pub title: Option<String>,
    pub body: Option<String>,
    pub yes: bool,
}

impl From<&PushArgs> for PushParams {
    /// Convert clap-derived `PushArgs` into the flat `PushParams`,
    /// collapsing `bookmark_pos` / `bookmark` (clap already enforces
    /// they don't both appear) into the single `bookmark` field.
    fn from(a: &PushArgs) -> Self {
        Self {
            bookmark: a.bookmark_pos.clone().or_else(|| a.bookmark.clone()),
            restart: a.restart,
            from: a.from,
            step: a.step,
            status: a.status,
            recheck: a.recheck,
            no_finalize: a.no_finalize,
            dry_run: a.dry_run,
            title: a.title.clone(),
            body: a.body.clone(),
            yes: a.yes,
        }
    }
}

impl SubcommandRunner for PushArgs {
    type Params = PushParams;

    /// Delegate to the existing `From<&PushArgs>` impl above
    /// (total — never fails).

    params: &PushParams,
) -> Result<(), Box<dyn std::error::Error>> {
    let bk = &state.bookmark;
    let app_arg = root.to_string_lossy();
    if params.dry_run {
        info!("push push-app: [dry-run] would run jj git push --bookmark {bk} -R {app_arg}");
        return Ok(());
    }
    info!("push push-app: jj git push --bookmark {bk} -R {app_arg}");
    run(
        "jj",
        &["git", "push", "--bookmark", bk, "-R", &app_arg],
        root,
    )?;
    Ok(())
}

/// Finalize `.claude` in-process, always pushing
/// `SESSION_BOOKMARK` (`main`) — the session repo's bookmark is
/// pinned, so `state.bookmark` plays no part here.
///
/// - Squashes the tail (session writes that landed since
///   `commit-claude`) into the session commit, then pushes — via
///   `finalize::finalize_inline`, so the ochid-drop guard
///   (Bugs #2) applies and a failure is a visible push failure.
/// - Replaces the detached `vc-x1 finalize --delay 10 --detach`
///   shell-out, whose child a sandboxed run silently killed at
///   command exit (Bugs #1) — and with it the `vc-x1`-on-PATH
///   dependency.
/// - `--no-finalize` turns this stage into a no-op so the
///   squash+push can be run manually.
fn stage_finalize_claude(
    root: &Path,
    _state: &PushState,
    params: &PushParams,
) -> Result<(), Box<dyn std::error::Error>> {
    if params.no_finalize {
        info!("push finalize-claude: skip (--no-finalize)");
        return Ok(());
    }
    let bk = SESSION_BOOKMARK;
    let claude = claude_path(root);
    let claude_arg = claude.to_string_lossy();
    if params.dry_run {
        info!(
            "push finalize-claude: [dry-run] would squash @ → @- and push {bk} in {claude_arg} (in-process)"
        );
        return Ok(());
    }
    info!("push finalize-claude: squash @ → @- + push {bk} -R {claude_arg} (in-process)");
    let fin = crate::finalize::FinalizeParams {
        repo: claude.clone(),
        squash: Some(SquashSpec {
            source: "@".to_string(),
            target: "@-".to_string(),
        }),
        delay_secs: 0.0,
        bookmark: Some(bk.to_string()),
        push: true,
        detach: false,
        exec: false,
    };
    crate::finalize::finalize_inline(&fin)
}

/// Verify the saved state still matches reality before any stage runs.
///
/// Catches the failure mode where out-of-band activity (manual finalize,
/// squash + force-push, abandon, etc.) moved the world forward between
/// the prior push and this resume, leaving `state` pointing at a
/// now-bogus halt point. The 0.37.1 dogfood incident is the canonical
/// example: push parked at `finalize-claude` after a failure; manual
/// recovery moved the world forward; the next push resumed at the
/// parked stage, no-op'd, and falsely declared "completed all stages"
/// while working copies still held uncommitted changes.
///
/// Three checks (per chores-06 [61] design):
///
/// 1. `state.app_chid` still resolves in the app repo (not abandoned).
/// 2. After `bookmark-set` has run (state.stage ∈ {PushApp,
///    FinalizeClaude}), the bookmark points at a commit whose chid
///    matches `state.app_chid`.
/// 3. `state.claude_chid` still resolves in `.claude`.
///
/// On any mismatch: error with the exact `vc-x1 push <bookmark>
/// --restart` remediation. A fresh state (no chids yet) is a no-op —
/// nothing to verify.
fn verify_state_sanity(root: &Path, state: &PushState) -> Result<(), Box<dyn std::error::Error>> {
    let Some(app_chid) = &state.app_chid else {
        return Ok(()); // OK: fresh state, nothing to verify yet
    };
    let bookmark = &state.bookmark;
    let root_str = root.to_string_lossy();
    let cwd = Path::new(".");

    // 1. app_chid still resolves.
    run(
        "jj",
        &[
            "log",
            "-r",
            app_chid,
            "--no-graph",
            "-T",
            "\"x\"",
            "-R",
            &root_str,
        ],
        cwd,
    )
    .map_err(|_| -> Box<dyn std::error::Error> {
        format!(
            "state-sanity: app_chid '{app_chid}' has been abandoned or no longer resolves \
             in the app repo. State is stale — run `vc-x1 push {bookmark} --restart` to clear."
        )
        .into()
    })?;

    // 2. bookmark at app_chid (after bookmark-set has run).
    if matches!(state.stage, Stage::PushApp | Stage::FinalizeClaude) {
        let bookmark_chid = run(
            "jj",
            &[
                "log",
                "-r",
                bookmark,
                "--no-graph",
                "-T",
                "change_id.short(12)",
                "-R",
                &root_str,
            ],
            cwd,
        )?;
        let bookmark_chid = bookmark_chid.trim();
        if bookmark_chid != app_chid.as_str() {
            return Err(format!(
                "state-sanity: bookmark '{bookmark}' is at chid '{bookmark_chid}' but \
                 state.app_chid is '{app_chid}'. State is stale — run \
                 `vc-x1 push {bookmark} --restart` to clear."
            )
            .into());
        }
    }

    // 3. claude_chid still resolves.
    if let Some(claude_chid) = &state.claude_chid {
        let claude = claude_path(root);
        let claude_str = claude.to_string_lossy();
        run(
            "jj",
            &[
                "log",
                "-r",
                claude_chid,
                "--no-graph",
                "-T",
                "\"x\"",
                "-R",
                &claude_str,
            ],
            cwd,
        )
        .map_err(|_| -> Box<dyn std::error::Error> {
            format!(
                "state-sanity: claude_chid '{claude_chid}' has been abandoned or no longer \
                 resolves in .claude. State is stale — run \
                 `vc-x1 push {bookmark} --restart` to clear."
            )
            .into()
        })?;
    }

    Ok(())
}

/// Verify the world matches the saved state after all stages have run.
///
/// Counterpart to `verify_state_sanity` (which runs pre-stage). This
/// runs after the stage loop completes and confirms the post-conditions
/// are real — directly addresses the 0.37.1 false-success symptom
/// (push declared "completed all stages" while the working copy still held
/// uncommitted changes from a stale-state resume).
///
/// Three checks:
///
/// 1. App's bookmark is at a commit whose chid matches `state.app_chid`.
/// 2. App's working copy has no uncommitted changes (commit-app should
///    have captured anything that was there).
/// 3. `.claude`'s bookmark is at `state.claude_chid`'s commit (when set).
///    `.claude`'s working copy (`@`) may legitimately have new
///    session writes that landed after finalize-claude's squash —
///    the tail rides into the next cycle's commit — so no
///    working-copy-clean check on `.claude`.
///
/// On any mismatch: returns `Err`. The caller surfaces as a loud
/// warning rather than blocking — push has already crossed the remote
/// boundary, work is live on origin, the warning prompts the user to
/// investigate.
fn verify_completion_sanity(
    root: &Path,
    state: &PushState,
) -> Result<(), Box<dyn std::error::Error>> {
    let bookmark = &state.bookmark;
    let root_str = root.to_string_lossy();
    let cwd = Path::new(".");

    // 1. app bookmark at state.app_chid.
    if let Some(app_chid) = &state.app_chid {
        let actual = run(
            "jj",
            &[
                "log",
                "-r",
                bookmark,
                "--no-graph",
                "-T",
                "change_id.short(12)",
                "-R",
                &root_str,
            ],
            cwd,
        )?;
        let actual = actual.trim();
        if actual != app_chid.as_str() {
            return Err(format!(
                "completion sanity: app bookmark '{bookmark}' is at chid '{actual}' but \
                 state.app_chid is '{app_chid}'."
            )
            .into());

//! `SubcommandRunner` trait
//!
//! The purpose is to simplify invoking a subcommand so `main`
//! can invoke any subcommand with one line:
//!
//! `Commands::Chid(args) => args.dispatch(&ctx),`
//!
//! Instead of the ~11 lines that the default `dispatch` below
//! now encapsulates.
//!
//! Implementors provide:
//!
//! - [`SubcommandRunner::to_params`] — build the clap-free
//!   `Params` from the clap `Args` (covers both `From` /
//!   `TryFrom` shapes uniformly via `Result<_, String>`).
//! - [`SubcommandRunner::run`] — the subcommand body.
//!
//! The default [`SubcommandRunner::dispatch`] builds `Params`
//! via `to_params`, runs via `run`, and maps the result to
//! `ExitCode`. Errors at any stage log via `error!` and return
//! `ExitCode::FAILURE`. `Context` is loaded once in `main` and
//! passed in by reference so a single `Context` is shared across
//! the (one) match arm that actually runs.
//!
//! ## See also
//!
//! - The wider CLI-args / subcommand-layer split this trait
//!   formalizes: [`ARCHITECTURE.md > args → Context + Params`][arch].
//! - Cycle design, ladder, evaluation gate:
//!   [`chores-10.md > 0.50.0-0`][open].
//! - Worked example, trait-shape decisions, naming:
//!   [`chores-10.md > 0.50.0-1`][port].
//! - First implementor: [`crate::chid`].
//!
//! [arch]: https://github.com/winksaville/vc-x1/blob/main/ARCHITECTURE.md#args--context--params
//! [open]: https://github.com/winksaville/vc-x1/blob/main/notes/chores/chores-10.md#chore-open-subcommand-trait-sweep-0500-0
//! [port]: https://github.com/winksaville/vc-x1/blob/main/notes/chores/chores-10.md#refactor-subcommandrunner-trait--chid-0500-1

use std::process::ExitCode;

use log::error;

use crate::context::Context;

/// Trait implemented by every subcommand's clap `Args` type so
/// `main.rs` can dispatch via a single `args.dispatch(&ctx)`
/// call.
pub trait SubcommandRunner {
    /// The clap-free `Params` struct the subcommand body
    /// consumes.
    type Params;

    /// Build `Params` from `Args`. `Result<_, String>` absorbs
    /// both `From` (return `Ok(...)`) and `TryFrom` (forward
    /// the error) shapes uniformly.
    fn to_params(&self) -> Result<Self::Params, String>;

    /// Run the subcommand body.
    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>>;

    /// Default dispatch: build `Params` via `to_params`, bracket
    /// the run with `crate::bm_track` enter/exit, execute via
    /// `run`, and map the result to `ExitCode`. Errors at any
    /// stage log via `error!` and return `ExitCode::FAILURE`.
    /// `bm_track` itself emits at `debug!`, so default runs stay
    /// quiet and the detached `finalize --exec` child (which runs
    /// without `-v`) silently no-ops — no per-call gate is needed
    /// here. `surface_previous_failures` for finalize's failure
    /// markers is handled in `main` before dispatch, so dispatch
    /// has no session-chrome responsibility at all anymore.
    fn dispatch(&self, ctx: &Context) -> ExitCode {
        let params = match self.to_params() {
            Ok(p) => p,
            Err(e) => {
                error!("{e}");
                return ExitCode::FAILURE;
            }
        };

        // Command name is the first positional after the binary;
        // clap has already validated it by the time we reach
        // dispatch (top-level parse errors exit earlier).
        let command_name = std::env::args().nth(1).unwrap_or_else(|| "?".to_string()); // OK: default when somehow invoked without a subcommand

        crate::bm_track("enter", &command_name);
        let exit_code = match Self::run(ctx, &params) {
            Ok(()) => ExitCode::SUCCESS,
            Err(e) => {
                error!("{e}");
                ExitCode::FAILURE
            }
        };
        crate::bm_track("exit ", &command_name);
        exit_code
    }
}

        )
        .into());
    }
    Ok(())
}

