/// `Stage::as_str` and `Stage::from_str` round-trip every variant.
#[test]
fn stage_str_roundtrip() {
    for stage in [
        Stage::Preflight,
        Stage::Review,
        Stage::Message,
        Stage::CommitApp,
        Stage::CommitClaude,
        Stage::BookmarkSet,
        Stage::PushApp,
        Stage::FinalizeClaude,
    ] {
        assert_eq!(Stage::from_str(stage.as_str()), Some(stage));
    }
}

