1	//! The `squash-push` subcommand: squash the working copy into its
2	//! parent, advance a bookmark, and push — capture a repo's trailing
3	//! writes and publish them in one step.
4	//!
5	//! - Built for the bot's `.claude` session repo, whose working copy
6	//!   accumulates session data continuously (the session tail); also
7	//!   useful on the app repo as a deliberate amend-and-push (a
8	//!   published-history rewrite, so the push is a forced update).
9	//! - Runs fully in-process: preflight validations, then squash +
10	//!   bookmark-set + push. A failure is a visible non-zero exit.
11	//! - Replaces the `finalize` subcommand (retired 0.69.0-2), whose
12	//!   detached `--delay`/`--detach` child a sandboxed run silently
13	//!   killed at command exit (Bugs #1). `surface_previous_failures`
14	//!   stays one deprecation cycle to drain failure markers older
15	//!   installed versions may still write.
16	
17	use std::path::{Path, PathBuf};
18	
19	use clap::Args;
20	use log::{debug, info};
21	
22	use crate::common::run;
23	use crate::context::Context;
24	use crate::options_flags::squash::{SquashOption, SquashSpec};
25	use crate::subcommand::SubcommandRunner;
26	
27	/// Directory where ≤0.69.0-1 `finalize --detach` children wrote
28	/// failure markers. Kept (with `surface_previous_failures`) for one
29	/// deprecation cycle so markers from older installed versions still
30	/// drain; nothing writes markers anymore.
31	fn status_dir() -> Option<PathBuf> {
32	    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
33	}
34	
35	/// Read, print, and delete any failure markers left by ≤0.69.0-1
36	/// detached finalize children. Cheap no-op when the directory
