51	        .map(|e| e.path())
52	        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
53	        .collect();
54	    paths.sort();
55	    if paths.is_empty() {
56	        return;
57	    }
58	    eprintln!("warn: ==== failure(s) from previous detached finalize run(s) ====");
59	    for path in paths {
