41	///   historical — failures from earlier detached runs, not this one.
42	pub fn surface_previous_failures() {
43	    let Some(dir) = status_dir() else {
44	        return;
45	    };
46	    let Ok(entries) = std::fs::read_dir(&dir) else {
47	        return;
48	    };
