/// edit here.
fn bin_dir() -> PathBuf {
    Path::new(env!(concat!("CARGO_BIN_EXE_", env!("CARGO_PKG_NAME"))))
        .parent()
        .expect("binary has a parent dir")
        .to_path_buf()
}

