//! The `squash-push` subcommand: squash the working copy into its
//! parent, advance a bookmark, and push — capture a repo's trailing
//! writes and publish them in one step.
//!
//! - Built for the bot's `.claude` session repo, whose working copy
//!   accumulates session data continuously (the session tail); also
//!   useful on the app repo as a deliberate amend-and-push (a
//!   published-history rewrite, so the push is a forced update).
//! - Runs fully in-process: preflight validations, then squash +
//!   bookmark-set + push. A failure is a visible non-zero exit.
//! - Replaces the `finalize` subcommand (retired 0.69.0-2), whose
//!   detached `--delay`/`--detach` child a sandboxed run silently
//!   killed at command exit (Bugs #1). `surface_previous_failures`
//!   stays one deprecation cycle to drain failure markers older
//!   installed versions may still write.

use std::path::{Path, PathBuf};

use clap::Args;
use log::{debug, info};

use crate::common::run;
use crate::context::Context;
use crate::options_flags::squash::{SquashOption, SquashSpec};
use crate::subcommand::SubcommandRunner;

/// Directory where ≤0.69.0-1 `finalize --detach` children wrote
/// failure markers. Kept (with `surface_previous_failures`) for one
/// deprecation cycle so markers from older installed versions still
/// drain; nothing writes markers anymore.
fn status_dir() -> Option<PathBuf> {
    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
}

/// Read, print, and delete any failure markers left by ≤0.69.0-1
/// detached finalize children. Cheap no-op when the directory
/// doesn't exist.
///
/// - Called after the current command's output (see `main`), so the
///   block opens with a loud banner marking everything below it as
///   historical — failures from earlier detached runs, not this one.
pub fn surface_previous_failures() {
    let Some(dir) = status_dir() else {
        return;
    };
    let Ok(entries) = std::fs::read_dir(&dir) else {
        return;
    };
    let mut paths: Vec<PathBuf> = entries
        .flatten()
        .map(|e| e.path())
        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
        .collect();
    paths.sort();
    if paths.is_empty() {
        return;
    }
    eprintln!("warn: ==== failure(s) from previous detached finalize run(s) ====");
