1	//! The `squash-push` subcommand: squash the working copy into its
2	//! parent, advance a bookmark, and push — capture a repo's trailing
3	//! writes and publish them in one step.
4	//!
5	//! - Built for the bot's `.claude` session repo, whose working copy
6	//!   accumulates session data continuously (the session tail); also
7	//!   useful on the app repo as a deliberate amend-and-push (a
8	//!   published-history rewrite, so the push is a forced update).
9	//! - Runs fully in-process: preflight validations, then squash +
10	//!   bookmark-set + push. A failure is a visible non-zero exit.
11	//! - Replaces the `finalize` subcommand (retired 0.69.0-2), whose
12	//!   detached `--delay`/`--detach` child a sandboxed run silently
13	//!   killed at command exit (Bugs #1). The detach failure-marker
14	//!   machinery went with it; any stale markers under
15	//!   `~/.cache/vc-x1/finalize-status` are inert and can be deleted
16	//!   by hand.
17	
18	use std::path::{Path, PathBuf};
19	
20	use clap::Args;
21	use log::{debug, info};
22	
23	use crate::common::run;
24	use crate::context::Context;
25	use crate::options_flags::squash::{SquashOption, SquashSpec};
26	use crate::subcommand::SubcommandRunner;
27	
28	/// Squash `@` into `@-`, advance BOOKMARK, and push.
29	///
30	/// Captures a repo's trailing working-copy writes into the last
31	/// commit and publishes it — rewriting an already-pushed commit is
32	/// a forced update. Zero-ceremony default: bare `vc-x1 squash-push`
33	/// squashes `@ → @-` and pushes `main` in `.`.
34	#[derive(Args, Debug)]
35	pub struct SquashPushArgs {
36	    /// Bookmark to advance and push
37	    #[arg(value_name = "BOOKMARK", default_value = "main")]
38	    pub bookmark: String,
39	
40	    /// Path to jj repo
41	    #[arg(short = 'R', long, default_value = ".")]
42	    pub repo: PathBuf,
43	
44	    #[command(flatten)]
45	    pub squash: SquashOption,
46	}
47	
48	/// Per-invocation squash-push inputs — the clap-free shape the op
49	/// works against. Built from `SquashPushArgs` at the binary edge
50	/// via `TryFrom` (fallible only on repo-path canonicalization);
51	/// `vc-x1 push`'s `squash-push-bot` stage constructs it
52	/// directly.
53	#[derive(Debug)]
54	pub struct SquashPushParams {
55	    pub repo: PathBuf,
56	    pub squash: SquashSpec,
57	    pub bookmark: String,
58	}
59	
60	impl TryFrom<&SquashPushArgs> for SquashPushParams {
61	    type Error = String;
62	
63	    /// Canonicalize `--repo` (early, visible failure on a bad path)
64	    /// and fill the `--squash` default; BOOKMARK maps straight over.
65	    fn try_from(a: &SquashPushArgs) -> Result<Self, String> {
66	        let repo = std::fs::canonicalize(&a.repo)
67	            .map_err(|e| format!("cannot resolve repo path '{}': {e}", a.repo.display()))?;
68	        Ok(SquashPushParams {
69	            repo,
70	            squash: a.squash.value.clone().unwrap_or_else(|| SquashSpec {
71	                source: "@".to_string(),
72	                target: "@-".to_string(),
73	            }), // OK: --squash absent → the command's default @,@- pair
74	            bookmark: a.bookmark.clone(),
75	        })
76	    }
77	}
78	
79	impl SubcommandRunner for SquashPushArgs {
80	    type Params = SquashPushParams;
81	
82	    /// Delegate to the `TryFrom<&SquashPushArgs>` impl above.
83	    fn to_params(&self) -> Result<Self::Params, String> {
84	        SquashPushParams::try_from(self)
85	    }
86	
87	    /// Run the `squash-push` op (`ctx` unused — the op is fully
88	    /// parameterized by `Params`).
89	    fn run(_ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
90	        squash_push(params)
91	    }
92	}
93	
94	/// Validate inputs before mutating anything.
95	///
96	/// Catches the common failure modes up front — unresolvable
97	/// revsets, an ochid-dropping squash, conflicts, a missing /
98	/// untracked / non-forward bookmark, an undescribed push target —
99	/// so the run fails before the squash rewrites history.
100	fn preflight(params: &SquashPushParams) -> Result<(), Box<dyn std::error::Error>> {
101	    debug!("preflight: checking params");
102	    let repo_str = params.repo.to_string_lossy();
103	    let cwd = std::path::Path::new(".");
104	    let sq = &params.squash;
105	    let bookmark = &params.bookmark;
106	
107	    // Verify squash revsets resolve to something, and that the squash
108	    // won't drop source-only ochid: trailers.
109	    jj_rev_exists(&repo_str, cwd, &sq.source)
110	        .map_err(|e| format!("squash source '{}' does not resolve: {e}", sq.source))?;
111	    jj_rev_exists(&repo_str, cwd, &sq.target)
112	        .map_err(|e| format!("squash target '{}' does not resolve: {e}", sq.target))?;
113	    check_squash_keeps_ochids(&repo_str, cwd, sq)?;
114	
115	    // Refuse to operate on a repo with conflicts.
116	    let conflicts = run(
117	        "jj",
118	        &[
119	            "log",
120	            "-r",
121	            "conflicts()",
122	            "--no-graph",
123	            "-T",
124	            "\"x\"",
125	            "-R",
126	            &repo_str,
127	        ],
128	        cwd,
129	    )?;
130	    if !conflicts.is_empty() {
131	        return Err(format!("repo '{repo_str}' has conflicts — resolve before squash-push").into());
132	    }
133	
134	    // Bookmark: existence, tracking, forward-only move, push-target description.
135	    let exists = run("jj", &["bookmark", "list", bookmark, "-R", &repo_str], cwd)?;
136	    if exists.is_empty() {
137	        return Err(format!("bookmark '{bookmark}' does not exist").into());
138	    }
139	
140	    crate::common::verify_tracking(&params.repo, bookmark)?;
141	
142	    let range = run(
143	        "jj",
144	        &[
145	            "log",
146	            "-r",
147	            &format!("{bookmark}::({})", sq.target),
148	            "--no-graph",
149	            "-T",
150	            "\"x\"",
151	            "-R",
152	            &repo_str,
153	        ],
154	        cwd,
155	    )?;
156	    if range.is_empty() {
157	        return Err(format!(
158	            "bookmark '{bookmark}' move is not forward — current position is not an \
159	             ancestor of '{}' (would diverge)",
160	            sq.target
161	        )
162	        .into());
163	    }
164	
165	    let desc = run(
166	        "jj",
167	        &[
168	            "log",
169	            "-r",
170	            &sq.target,
171	            "--no-graph",
172	            "-T",
173	            "description",
174	            "-R",
175	            &repo_str,
176	        ],
177	        cwd,
178	    )?;
179	    if desc.trim().is_empty() {
180	        return Err(format!(
181	            "push target '{}' has no description — push would fail \
182	             (run `jj describe -r {} -R {repo_str}` first)",
183	            sq.target, sq.target
184	        )
185	        .into());
186	    }
187	
188	    Ok(())
189	}
190	
191	/// Extract the values of column-0 `ochid:` trailer lines from a
192	/// commit description, in order of appearance.
193	fn extract_ochids(desc: &str) -> Vec<String> {
194	    desc.lines()
195	        .filter_map(|line| line.strip_prefix("ochid:"))
196	        .map(|value| value.trim().to_string())
197	        .filter(|value| !value.is_empty())
198	        .collect()
199	}
200	
201	/// Return the `ochid:` trailer values present in `source_desc` but
202	/// absent from `target_desc` — the trailers a squash with
203	/// `--use-destination-message` would silently drop (Bugs #2).
204	fn ochids_at_risk(source_desc: &str, target_desc: &str) -> Vec<String> {
205	    let kept = extract_ochids(target_desc);
206	    extract_ochids(source_desc)
207	        .into_iter()
208	        .filter(|ochid| !kept.contains(ochid))
209	        .collect()
210	}
211	
212	/// Refuse a squash that would drop the source message's `ochid:`
213	/// trailers.
214	///
215	/// - Compares the two messages' `ochid:` trailers; errors when the
216	///   source carries any the destination's message lacks —
217	///   `--use-destination-message` would discard them, leaving the
218	///   counterpart repo's cross-links dangling (Bugs #2).
219	fn check_squash_keeps_ochids(
220	    repo: &str,
221	    cwd: &std::path::Path,
222	    sq: &SquashSpec,
223	) -> Result<(), Box<dyn std::error::Error>> {
224	    let desc_of = |rev: &str| {
225	        run(
226	            "jj",
227	            &[
228	                "log",
229	                "-r",
230	                rev,
231	                "--no-graph",
232	                "-T",
233	                "description",
234	                "-R",
235	                repo,
236	            ],
237	            cwd,
238	        )
239	    };
240	    let at_risk = ochids_at_risk(&desc_of(&sq.source)?, &desc_of(&sq.target)?);
241	    if at_risk.is_empty() {
242	        return Ok(());
243	    }
244	    let listed = at_risk
245	        .iter()
246	        .map(|ochid| format!("  {ochid}"))
247	        .collect::<Vec<_>>()
248	        .join("\n");
249	    Err(format!(
250	        "refusing squash {} → {}: the squash would drop ochid: trailers\n\
251	         the destination's message lacks:\n\
252	         {listed}\n\
253	         merge the messages by hand (`jj describe {} -R {}`) or clear\n\
254	         the source's description, then retry",
255	        sq.source, sq.target, sq.target, repo,
256	    )
257	    .into())
258	}
259	
260	/// Return Ok(()) if the revset resolves to one or more commits in `repo`.
261	fn jj_rev_exists(repo: &str, cwd: &std::path::Path, rev: &str) -> Result<(), String> {
262	    run(
263	        "jj",
264	        &["log", "-r", rev, "--no-graph", "-T", "\"x\"", "-R", repo],
265	        cwd,
266	    )
267	    .map_err(|e| e.to_string())?;
268	    Ok(())
269	}
270	
271	/// True when `rev` has no file changes and no description — nothing
272	/// worth squashing.
273	fn rev_is_empty_undescribed(
274	    repo: &str,
275	    cwd: &Path,
276	    rev: &str,
277	) -> Result<bool, Box<dyn std::error::Error>> {
278	    let empty = run(
279	        "jj",
280	        &["log", "-r", rev, "--no-graph", "-T", "empty", "-R", repo],
281	        cwd,
282	    )?;
283	    if empty.trim() != "true" {
284	        return Ok(false);
285	    }
286	    let desc = run(
287	        "jj",
288	        &[
289	            "log",
290	            "-r",
291	            rev,
292	            "--no-graph",
293	            "-T",
294	            "description",
295	            "-R",
296	            repo,
297	        ],
298	        cwd,
299	    )?;
300	    Ok(desc.trim().is_empty())
301	}
302	
303	/// Full commit id of a revset in `repo`.
304	fn jj_commit_id(repo: &str, cwd: &Path, rev: &str) -> Result<String, Box<dyn std::error::Error>> {
305	    Ok(run(
306	        "jj",
307	        &[
308	            "log",
309	            "-r",
310	            rev,
311	            "--no-graph",
312	            "-T",
313	            "commit_id",
314	            "-R",
315	            repo,
316	        ],
317	        cwd,
318	    )?
319	    .trim()
320	    .to_string())
321	}
322	
323	/// Run the `squash-push` op: preflight, then squash (skipped when
324	/// the source is empty and undescribed) + bookmark-set + push.
325	///
326	/// - With an empty source and the bookmark already matching both
327	///   the squash target and the remote, reports "already sync'd"
328	///   and exits 0 — nothing to do.
329	/// - With an empty source but the remote behind, skips the squash
330	///   and still pushes.
331	pub fn squash_push(params: &SquashPushParams) -> Result<(), Box<dyn std::error::Error>> {
332	    debug!("squash_push: entry params={params:?}");
333	    let repo_str = params.repo.to_string_lossy().to_string();
334	    let cwd = std::path::Path::new(".");
335	    let sq = &params.squash;
336	    let bookmark = &params.bookmark;
337	
338	    preflight(params)?;
339	
340	    // Empty-source handling: nothing to squash. If the bookmark
341	    // already matches both the target and the remote, nothing to
342	    // push either — report and exit 0.
343	    if rev_is_empty_undescribed(&repo_str, cwd, &sq.source)? {
344	        let target_cid = jj_commit_id(&repo_str, cwd, &sq.target)?;
345	        let bookmark_cid = jj_commit_id(&repo_str, cwd, bookmark)?;
346	        let remote_cid =
347	            jj_commit_id(&repo_str, cwd, &format!("{bookmark}@origin")).unwrap_or_default(); // OK: unresolvable remote bookmark (never pushed) → treated as not sync'd
348	        if bookmark_cid == target_cid && bookmark_cid == remote_cid {
349	            info!("squash-push: repo '{repo_str}' is already sync'd with remote");
350	            return Ok(());
351	        }
352	        info!(
353	            "squash-push: {} is empty — skipping squash, still pushing",
354	            sq.source
355	        );
356	    } else {
357	        info!("squash-push: squashing {} → {}...", sq.source, sq.target);
358	        run(
359	            "jj",
360	            &[
361	                "squash",
362	                "--ignore-immutable",
363	                "--use-destination-message",
364	                "--from",
365	                &sq.source,
366	                "--into",
367	                &sq.target,
368	                "-R",
369	                &repo_str,
370	            ],
371	            cwd,
372	        )?;
373	    }
374	
375	    info!(
376	        "squash-push: setting bookmark '{bookmark}' to {}...",
377	        sq.target
378	    );
379	    run(
380	        "jj",
381	        &[
382	            "bookmark", "set", bookmark, "-r", &sq.target, "-R", &repo_str,
383	        ],
384	        cwd,
