    #[test]
    fn retired_flags_rejected() {
        for flag in ["--detach", "--delay", "--exec", "--push"] {
            let err = parse_err(&["vc-x1", "squash-push", flag]);
            assert!(err.contains(flag), "flag {flag}: {err}");
