163	pub struct FixturePor {
164	    /// Root tempdir that owns the repo and its bare-git remote.
165	    pub base: PathBuf,
166	    /// POR repo path (`<base>/work`).
167	    pub work: PathBuf,
168	}
169	
170	impl FixturePor {
171	    /// Build a fresh POR fixture in a unique tempdir.
